from agent import *from models.products import *import redebug = TrueSITE = 'http://www.nintendoworldreport.com'def run(context, session):   session.browser.agent = 'Mozilla/5.0 (Macintosh; Intel Mac OS X 10.6; rv:18.0) Gecko/20100101 Firefox/18.0'   session.sessionbreakers = [SessionBreak(max_requests=8000)]   session.queue(Request('http://www.nintendoworldreport.com/review?region=All&system=All&status=All&type=All'), process_revlist, {})def process_revlist(data, context, session):   for rev in data.xpath("//table[@id='results']/tr[position()>1]"):      name = rev.xpath("td[1]/a/text()").string(multiple=True)      url = rev.xpath("td[1]/a[not(regexp:test(@href,'recommendations'))]/@href").string()      author = rev.xpath("td[4]//text()").string(multiple=True)      platform = rev.xpath("td[2]//text()").string(multiple=True)      date = rev.xpath("td[5]//text()").string(multiple=True)      score = rev.xpath("td[6]//text()").string(multiple=True)      if url and name:         session.queue(Request(url), process_review, dict(url=url, name=name, author=author, category=platform, date=date, score=score))def process_review(data, context, session):   product = Product()   product.name = context['name']   product.category = context['category']   product.url = context['url']   product.ssid = context['url'].split('/')[4]   product.manufacturer = data.xpath("//td[regexp:test(normalize-space(.),'Developer')]/following-sibling::td//text()").string(multiple=True)   content = data.xpath("//div[@id='article']").first()   if content:      review = Review()      product.reviews.append(review)      review.title = product.name      review.type = 'pro'      review.url = product.url      review.ssid = product.ssid      review.date = context['date']      author = content.xpath("preceding-sibling::p/a").first()      if author:         name = author.xpath("descendant::text()").string(multiple=True)         url = author.xpath("@href").string(multiple=True)         if name and url:            ssid = re_search_once('staff\/(\d+)', url)            review.authors.append(Person(name=name, profile_url=url, ssid=ssid))      else:         author = context['author']         if author:            review.authors.append(Person(name=author, ssid=author))      summary = content.xpath("p[@class='biline']//text()").string(multiple=True)      if summary:         review.properties.append(ReviewProperty(type='summary', value=summary))      excerpt = content.xpath("div[@id='body']/p//text()").string(multiple=True)      if excerpt:         review.properties.append(ReviewProperty(type='excerpt', value=excerpt))      else:         print('XXX1')      for pro in content.xpath("following-sibling::div[@id='summary']//ul[@class='pro']/li"):         text = pro.xpath("descendant::text()").string(multiple=True)         if text:            review.properties.append(ReviewProperty(type='pros', value=text))      for con in content.xpath("following-sibling::div[@id='summary']//ul[@class='con']/li"):         text = con.xpath("descendant::text()").string(multiple=True)         if text:            review.properties.append(ReviewProperty(type='cons', value=text))      lastpage = content.xpath("following-sibling::div[@id='summary']/a[@class='conclusion']/@href").string()      if lastpage:         print('XXX1')         review.properties.append(ReviewProperty(type='pages', value={'url':context['url'], 'title':'Page 1'}))         review.properties.append(ReviewProperty(type='pages', value={'url':lastpage, 'title':'Page 2'}))         session.do(Request(lastpage, max_age=0), process_lastpage, {'review':review, 'url':lastpage})        else:         print('XXX2')         score = context.get('score', None)         if score:            review.grades.append(Grade(name='Score', type='overall', value=float(score), best=10))      session.emit(product)def process_lastpage(data, context, session):   review = context['review']   for rating in data.xpath("//h5"):      title = rating.xpath("descendant::text()").string(multiple=True)      score = rating.xpath("following-sibling::div[@class='score'][1]//text()").string(multiple=True)      description = rating.xpath("following-sibling::p[1]//text()").string(multiple=True)      if title == 'Final' and score:         review.grades.append(Grade(name=title, type='overall', value=float(score), best=10, description=description))      elif title and score:         review.grades.append(Grade(name=title, value=float(score), best=10, description=description))      conclusion = data.xpath("//h5[regexp:test(normalize-space(.),'Final')]/following-sibling::p[1]//text()").string(multiple=True)   if conclusion:      review.properties.append(ReviewProperty(type='conclusion', value=conclusion))   else:      print('XXX3') 